const cfg = $input.item.json;

const CM_BASE = "https://clickmarket-backend-8scjo.ondigitalocean.app/api";
const SUPABASE_URL = cfg.supabase_url;
const SUPABASE_SERVICE_ROLE_KEY = cfg.supabase_service_role_key;
const PER_PAGE = 100;
const UPSERT_BATCH_SIZE = 500;
const MIN_ORDER_DATE = "2025-07-01"; // plancher demandé par le CEO — pas de borne haute, on synchronise jusqu'à aujourd'hui

// ─── 1. Login — le token Bearer de ClickMarket n'est pas fiable dans la
// durée, on se reconnecte donc à chaque exécution du workflow.
const loginRes = await this.helpers.httpRequest({
  method: "POST",
  url: `${CM_BASE}/login`,
  headers: { "Content-Type": "application/json", Accept: "application/json" },
  body: {
    email: cfg.clickmarket_email,
    password: cfg.clickmarket_password,
  },
  json: true,
});

const token = loginRes.token;
if (!token) {
  throw new Error("ClickMarket login: aucun token reçu — vérifiez l'email/mot de passe dans le nœud 'Config'.");
}

// La réponse de /login contient déjà les marchés accessibles au compte :
// countries: [{ id, name, currency }, ...] — pas besoin de les coder en dur.
const countries = loginRes.countries || [];

// ─── 2. Pour chaque marché, paginer jusqu'à la dernière page ───────────────
const allRows = [];

for (const country of countries) {
  let page = 1;
  let lastPage = 1;

  do {
    const res = await this.helpers.httpRequest({
      method: "GET",
      url: `${CM_BASE}/orders-paginated`,
      qs: { per_page: PER_PAGE, page, orders_type: "leads" },
      headers: {
        Authorization: `Bearer ${token}`,
        Accept: "application/json",
        "X-Selected-Country": JSON.stringify({
          id: country.id,
          name: country.name,
          currency: country.currency,
        }),
      },
      json: true,
    });

    lastPage = res.pagination?.last_page ?? 1;

    for (const o of res.orders || []) {
      const firstItem =
        Array.isArray(o.order_items) && o.order_items.length > 0
          ? o.order_items[0]
          : null;
      const productName = firstItem?.product?.name ?? null;

      const agent = o.confirmation_agent;
      const agentName = agent
        ? [agent.first_name, agent.last_name].filter(Boolean).join(" ")
        : null;

      const orderDate = o.order_date ? o.order_date.slice(0, 10) : null;
      if (!orderDate || orderDate < MIN_ORDER_DATE) continue;

      allRows.push({
        order_id: o.order_id,
        internal_id: o.id,
        country_id: o.country_id,
        country_name: o.country?.name ?? country.name,
        customer_name: o.customer_name,
        customer_city: o.customer_city,
        total_price: o.total_price,
        quantity: o.quantity,
        confirmation_status: o.confirmation_status?.name ?? null,
        shipping_status: o.shipping_status?.name ?? null,
        seller_payment_status: o.seller_payment_status,
        product_name: productName,
        confirmation_agent: agentName,
        order_date: orderDate,
        order_created_at: o.created_at,
        confirmed_at: o.confirmed_at,
        delivered_at: o.delivered_at,
      });
    }

    page += 1;
  } while (page <= lastPage);
}

// ─── 3. Upsert en masse vers Supabase, par lots de 500 lignes ──────────────
// Dédup par order_id d'abord : la pagination peut chevaucher deux pages (une commande qui
// bouge dans le tri de l'API pendant le scan complet, ex. un agent la confirme), et on ne veut
// pas que la même commande apparaisse deux fois dans un même lot (Postgres refuse "ON CONFLICT
// DO UPDATE ... affect row a second time" dans ce cas — observé en production sur Africod
// Congo). On garde la dernière occurrence.
const dedupedRows = Array.from(new Map(allRows.map((r) => [r.order_id, r])).values());

let upserted = 0;

for (let i = 0; i < dedupedRows.length; i += UPSERT_BATCH_SIZE) {
  const batch = dedupedRows.slice(i, i + UPSERT_BATCH_SIZE);

  await this.helpers.httpRequest({
    method: "POST",
    url: `${SUPABASE_URL}/rest/v1/clickmarket_leads`,
    headers: {
      "Content-Type": "application/json",
      apikey: SUPABASE_SERVICE_ROLE_KEY,
      Authorization: `Bearer ${SUPABASE_SERVICE_ROLE_KEY}`,
      Prefer: "resolution=merge-duplicates,return=minimal",
    },
    body: batch,
    json: true,
  });

  upserted += batch.length;
}

return [
  {
    json: {
      synced_orders: upserted,
      markets: countries.map((c) => c.name),
      finished_at: new Date().toISOString(),
    },
  },
];
